<?php
namespace App\Http\Controllers;use App\Models\GoogleCalendarConnection;use App\Services\GoogleCalendarService;use Illuminate\Http\{JsonResponse,RedirectResponse,Request};use Illuminate\Support\Facades\Cache;use Illuminate\Support\Str;
class GoogleCalendarController extends Controller{private function current():?GoogleCalendarConnection{return GoogleCalendarConnection::where('is_active',true)->latest()->first();}private function safe(?GoogleCalendarConnection $x):array{return['connected'=>(bool)$x,'account_name'=>$x?->google_account_name,'account_email'=>$x?->google_account_email,'connected_at'=>$x?->connected_at,'last_refreshed_at'=>$x?->last_refreshed_at,'selected_calendar_ids'=>$x?->selected_calendar_ids??[],'requires_reconnection'=>(bool)$x?->last_error,'last_error'=>$x?->last_error];}public function status():JsonResponse{return response()->json($this->safe($this->current()));}public function connect(Request $r,GoogleCalendarService $g):JsonResponse{$state=Str::random(64);Cache::put('google-calendar-state:'.$state,$r->user()->id,now()->addMinutes(10));return response()->json(['authorization_url'=>$g->authUrl($state)]);}public function callback(Request $r,GoogleCalendarService $g):RedirectResponse{$userId=Cache::pull('google-calendar-state:'.$r->string('state'));$url=config('app.frontend_url','http://localhost:5173').'/settings';if(!$userId||!$r->filled('code'))return redirect($url.'?google_calendar=error');try{$g->connect($r->string('code'),$userId);return redirect($url.'?google_calendar=connected');}catch(\Throwable){return redirect($url.'?google_calendar=error');}}public function calendars(GoogleCalendarService $g):JsonResponse{$x=$this->current();return response()->json($x?$g->calendars($x):[]);}public function select(Request $r):JsonResponse{$d=$r->validate(['calendar_ids'=>['required','array'],'calendar_ids.*'=>['string','max:1024']]);$x=$this->current();abort_unless($x,409,'Google Calendar is not connected.');$x->update(['selected_calendar_ids'=>array_values(array_unique($d['calendar_ids']))]);return response()->json($this->safe($x->fresh()));}public function disconnect():JsonResponse{$x=$this->current();if($x)$x->update(['is_active'=>false,'access_token'=>['revoked'=>true],'refresh_token'=>null]);return response()->json(['connected'=>false]);}}
